mapper.insert:

  SELECT SEQ_COMPANY.nextval FROM DUAL

insert into COMPANY (
  COMPANY_NO
  ,BUSINESS_NO
  ,COMPANY_NAME
  ,REPRESENTATIVE_NAME
  ,PHONE
  ,EMAIL
  ,CREATED_ON
) VALUES(
  #{companyNo}
  ,#{businessNo}
  ,#{companyName}
  ,#{representativeName}
  ,#{phone}
  ,#{email}
  ,#{createdOn}
)
